package com.cognizant.springlearn.controller; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.*; import org.springframework.web.bind.annotation.*;
@RestControllerAdvice public class ApiErrorHandler {@ExceptionHandler(NoSuchElementException.class) ResponseEntity<Map<String,String>> missing(NoSuchElementException e){return ResponseEntity.status(404).body(Map.of("message",e.getMessage()));}@ExceptionHandler({IllegalArgumentException.class,MethodArgumentNotValidException.class})ResponseEntity<Map<String,String>> invalid(Exception e){return ResponseEntity.badRequest().body(Map.of("message",e.getMessage()));}}
